  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return mCurIrb->CreateNeg(sub);
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  auto sub = self(obj->sub);

  switch (obj->kind) {
    case ImplicitCastExpr::kLValueToRValue:
      return mCurIrb->CreateLoad(self(obj->type), sub);
    default:
